## Context

This is the foundational bead for the full UI improvement. All subsequent beads reference `text-accent-violet` and `bg-accent-violet` Tailwind utility classes, which are generated from the tokens defined here. Complete this bead first.

## What to Do

Edit `src/app/globals.css` to add violet/indigo accent tokens:

**In `:root` block, REPLACE these existing neutral tokens:**
```css
--primary:              oklch(0.6 0.22 270);
--primary-foreground:   oklch(0.98 0.01 270);
--accent:               oklch(0.94 0.04 270);
--accent-foreground:    oklch(0.35 0.18 270);
--ring:                 oklch(0.6 0.22 270);
```

**In `:root` block, ADD these new violet alias tokens:**
```css
--accent-violet:        oklch(0.6 0.22 270);
--accent-violet-dark:   oklch(0.55 0.25 270);
--accent-violet-muted:  oklch(0.94 0.04 270);
```

**In `.dark` block, REPLACE:**
```css
--primary:              oklch(0.65 0.22 270);
--primary-foreground:   oklch(0.98 0.01 270);
--accent:               oklch(0.269 0.06 270);
--accent-foreground:    oklch(0.88 0.06 270);
--ring:                 oklch(0.55 0.22 270);
```

**In `.dark` block, ADD:**
```css
--accent-violet:        oklch(0.65 0.22 270);
--accent-violet-dark:   oklch(0.55 0.25 270);
--accent-violet-muted:  oklch(0.30 0.08 270);
```

**In `@theme inline {}` block, ADD:**
```css
--color-accent-violet:       var(--accent-violet);
--color-accent-violet-dark:  var(--accent-violet-dark);
--color-accent-violet-muted: var(--accent-violet-muted);
```

## Side Effects (free, no changes needed)

- `Checkbox` checked state (`data-[state=checked]:bg-primary`) → automatically violet
- `Button` default variant (`bg-primary`) → automatically violet Add button
- Focus rings (`--ring`) → violet

## Technical Notes

- Tailwind v4 CSS-first: NO tailwind.config.js. All tokens live in globals.css under `@theme inline {}`
- All glassmorphism tokens (`--glass-bg`, `--glass-border`, etc.) are UNCHANGED
- Run `npm run build` to verify Tailwind parses the new tokens correctly

## Acceptance Criteria

- [ ] `--primary`, `--accent`, `--ring` in `:root` have hue 270 and non-zero chroma
- [ ] Same tokens updated in `.dark` block
- [ ] `--color-accent-violet`, `--color-accent-violet-dark`, `--color-accent-violet-muted` added to `@theme inline`
- [ ] Existing glassmorphism tokens unchanged
- [ ] `npm run build` passes with no Tailwind parse errors
- [ ] `npm run typecheck` passes (CSS-only change)

Build the functional todo item component with toggle, edit, delete, due date display, and keyboard Delete shortcut.

## Steps
1. Create `src/components/todo-item.tsx`:

```tsx
'use client'
import { useTransition, useState, useRef } from 'react'
import { Checkbox } from '@/components/ui/checkbox'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Trash2, Pencil, Check, X } from 'lucide-react'
import { toggleTodo, deleteTodo, updateTodo } from '@/actions/todos'
import type { Todo } from '@/lib/schema'

// Due date color utility
function dueDateColor(dueDate: string | null): string {
  if (!dueDate) return ''
  const today = new Date().toISOString().slice(0, 10)
  if (dueDate < today) return 'text-red-400'
  if (dueDate === today) return 'text-amber-400'
  return 'text-green-400'
}

interface Props { todo: Todo }

export function TodoItem({ todo }: Props) {
  const [isPending, startTransition] = useTransition()
  const [isEditing, setIsEditing] = useState(false)
  const editRef = useRef<HTMLInputElement>(null)

  function handleDelete(e: React.KeyboardEvent | React.MouseEvent) {
    startTransition(async () => { await deleteTodo(todo.id) })
  }

  function handleToggle() {
    startTransition(async () => { await toggleTodo(todo.id, !todo.completed) })
  }

  function handleEditSave() {
    const newTitle = editRef.current?.value.trim()
    if (!newTitle) return
    startTransition(async () => {
      await updateTodo(todo.id, newTitle, todo.due_date ?? undefined)
      setIsEditing(false)
    })
  }

  return (
    <li
      className="flex items-center gap-3 p-3 rounded-xl bg-white/5 border border-white/10 hover:bg-white/10 transition-colors group"
      onKeyDown={e => {
        if (e.key === 'Delete' && e.target === e.currentTarget) handleDelete(e)
      }}
      tabIndex={0}
    >
      <Checkbox
        checked={!!todo.completed}
        onCheckedChange={handleToggle}
        disabled={isPending}
        className="border-white/30"
      />
      {isEditing ? (
        <Input
          ref={editRef}
          defaultValue={todo.title}
          className="flex-1 h-7 text-sm bg-transparent border-white/20 text-white"
          onKeyDown={e => {
            if (e.key === 'Enter') handleEditSave()
            if (e.key === 'Escape') setIsEditing(false)
          }}
          autoFocus
        />
      ) : (
        <span className={`flex-1 text-sm text-white ${todo.completed ? 'line-through opacity-50' : ''}`}>
          {todo.title}
        </span>
      )}
      {todo.due_date && (
        <span className={`text-xs ${dueDateColor(todo.due_date)}`}>{todo.due_date}</span>
      )}
      {isEditing ? (
        <>
          <Button variant="ghost" size="icon" className="h-7 w-7 text-white/60 hover:text-white" onClick={handleEditSave}><Check className="h-3 w-3" /></Button>
          <Button variant="ghost" size="icon" className="h-7 w-7 text-white/60 hover:text-white" onClick={() => setIsEditing(false)}><X className="h-3 w-3" /></Button>
        </>
      ) : (
        <>
          <Button variant="ghost" size="icon" className="h-7 w-7 text-white/60 hover:text-white opacity-0 group-hover:opacity-100" onClick={() => setIsEditing(true)}><Pencil className="h-3 w-3" /></Button>
          <Button variant="ghost" size="icon" className="h-7 w-7 text-white/60 hover:text-red-400 opacity-0 group-hover:opacity-100" onClick={handleDelete}><Trash2 className="h-3 w-3" /></Button>
        </>
      )}
    </li>
  )
}
```

## Acceptance Criteria
- [ ] Checkbox toggles `completed` state via `toggleTodo` server action
- [ ] Completed todos show `line-through` styling
- [ ] Edit mode: click pencil icon → inline input → Enter saves, Esc cancels
- [ ] Delete button calls `deleteTodo`
- [ ] `Delete` keyboard key on focused `<li>` deletes the item
- [ ] `due_date` rendered with correct color (green/amber/red or none)
- [ ] Edit/delete buttons only visible on hover (`group-hover:opacity-100`)
- [ ] `useTransition` prevents UI blocking during server actions

## Technical Notes
### UI Standard
Follow brainstorm.md UI/UX decisions: glassmorphism item card (bg-white/5, border-white/10), color-coded due dates (green=future, amber=today, red=overdue), dark mode. Reference: history/20260227-todo-app-nextjs16/brainstorm.md

- `completed` is `0/1` integer — use `!!todo.completed` to convert to boolean
- `dueDateColor` compares ISO strings directly (lexicographic = chronological for YYYY-MM-DD)
- Animations (Framer Motion) are added in bead 15 — this bead implements functionality only
- `tabIndex={0}` on `<li>` enables keyboard focus for Delete shortcut
- Guard Delete key: `e.target === e.currentTarget` prevents firing when deleting text in edit input

Build the RSC list container that renders filtered todos or an empty state message.

## Steps
1. Create `src/components/todo-list.tsx`:

```tsx
'use client'
import { useUIStore } from '@/store/ui'
import { TodoItem } from '@/components/todo-item'
import { AnimatePresence } from 'framer-motion'
import type { Todo } from '@/lib/schema'

interface Props { todos: Todo[] }

export function TodoList({ todos }: Props) {
  const { filter } = useUIStore()

  const filtered = todos.filter(todo => {
    if (filter === 'active')    return !todo.completed
    if (filter === 'completed') return  todo.completed
    return true
  })

  if (filtered.length === 0) {
    return (
      <p className="text-center text-white/40 py-8 text-sm">
        {filter === 'completed' ? 'No completed tasks yet.' :
         filter === 'active'    ? 'All caught up!' :
         'No todos yet — add one above!'}
      </p>
    )
  }

  return (
    <ul className="space-y-2">
      <AnimatePresence initial={false}>
        {filtered.map(todo => (
          <TodoItem key={todo.id} todo={todo} />
        ))}
      </AnimatePresence>
    </ul>
  )
}
```

## Acceptance Criteria
- [ ] Renders only todos matching current Zustand `filter`
- [ ] Shows context-aware empty state message when no matching todos
- [ ] `AnimatePresence` wraps list for exit animations (bead 15 adds the motion)
- [ ] Reads filter from Zustand (not props) — stays reactive to tab changes

## Technical Notes
### UI Standard
Follow brainstorm.md UI/UX decisions: glassmorphism card, Framer Motion microinteractions, color-coded due dates, dark mode. Reference: history/20260227-todo-app-nextjs16/brainstorm.md

- `'use client'` required to read Zustand filter state reactively
- `AnimatePresence` should be installed even if Framer Motion animations are added
  in bead 15 — this prepares the structure so bead 15 only needs to add motion props
- `initial={false}` on AnimatePresence prevents initial mount animations
- `completed` is integer 0/1 — use `!todo.completed` (truthy 0=false, 1=true works in JS)

Finalize the glassmorphism visual design by adding custom tokens to globals.css and applying them to the layout.

## Steps
1. Update `src/app/globals.css` to add custom glassmorphism tokens in `@theme`:

```css
@import "tailwindcss";
@import "tw-animate-css";

@theme {
  /* Glassmorphism surface tokens */
  --color-glass-bg: oklch(100% 0 0 / 0.08);
  --color-glass-bg-dark: oklch(100% 0 0 / 0.04);
  --color-glass-border: oklch(100% 0 0 / 0.18);
  --color-glass-hover: oklch(100% 0 0 / 0.12);

  /* Due date status colors */
  --color-due-overdue: oklch(65% 0.22 29);   /* red-400 */
  --color-due-today:   oklch(80% 0.17 84);   /* amber-400 */
  --color-due-future:  oklch(72% 0.18 151);  /* green-400 */

  /* Blur intensity */
  --blur-glass: 20px;
}
```

2. Verify backdrop-blur and bg-white/* utilities still work (should via Tailwind v4 defaults)
3. Do a final visual pass in both dark and light mode:
   - Card container: `backdrop-blur-xl bg-white/10 border-white/20`
   - Item cards: `bg-white/5 border-white/10`
   - Gradient bg: `from-slate-900 to-slate-800`
4. Ensure dark mode (`.dark` class on html) swaps surface opacities correctly

## Acceptance Criteria
- [ ] `@theme` block defines glassmorphism tokens in `globals.css`
- [ ] `backdrop-blur-xl` renders the frosted-glass effect on the card
- [ ] Dark mode shows slightly more transparent surfaces than light mode
- [ ] No `tailwind.config.js` present (v4 CSS-first)
- [ ] Visual appearance matches brainstorm.md spec:
  - Frosted-glass card for todo list container
  - Gradient background (dark slate)
  - Subtle item cards with hover highlight

## Technical Notes
### UI Standard
Follow brainstorm.md UI/UX decisions: glassmorphism card (backdrop-blur, semi-transparent bg, border-white/20). Reference: history/20260227-todo-app-nextjs16/brainstorm.md

- OKLCH colors are the native color space for Tailwind v4 — do not use hex or hsl
- `backdrop-blur` requires a semi-transparent background to be visible —
  `bg-white/10` (10% opacity) is the sweet spot for dark glassmorphism
- Test in both Chrome and Firefox — webkit-backdrop-filter may be needed:
  add `[backdrop-filter:blur(20px)] [-webkit-backdrop-filter:blur(20px)]` if blur fails
- Custom tokens in `@theme` are automatically available as Tailwind utilities:
  `bg-glass-bg`, `border-glass-border`, etc.

Build the add-todo form with title input, due date picker, keyboard shortcuts, and server action integration.

## Steps
1. Create `src/components/todo-form.tsx`:

```tsx
'use client'
import { useRef, useEffect, useTransition } from 'react'
import { Input } from '@/components/ui/input'
import { Button } from '@/components/ui/button'
import { createTodo } from '@/actions/todos'
import { Plus } from 'lucide-react'

export function TodoForm() {
  const titleRef = useRef<HTMLInputElement>(null)
  const dateRef  = useRef<HTMLInputElement>(null)
  const [isPending, startTransition] = useTransition()

  // Keyboard shortcut: 'n' to focus title input
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement
      if (e.key === 'n' && target.tagName !== 'INPUT' && target.tagName !== 'TEXTAREA') {
        e.preventDefault()
        titleRef.current?.focus()
      }
    }
    document.addEventListener('keydown', handler)
    return () => document.removeEventListener('keydown', handler)
  }, [])

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    const title   = titleRef.current?.value.trim()
    const dueDate = dateRef.current?.value || undefined
    if (!title) return
    startTransition(async () => {
      await createTodo(title, dueDate)
      if (titleRef.current) titleRef.current.value = ''
      if (dateRef.current)  dateRef.current.value  = ''
    })
  }

  return (
    <form onSubmit={handleSubmit} className="flex gap-2 mb-4">
      <Input
        ref={titleRef}
        placeholder="Add a task… (press n)"
        disabled={isPending}
        className="flex-1 bg-white/10 border-white/20 text-white placeholder:text-white/40"
        onKeyDown={e => e.key === 'Escape' && titleRef.current?.blur()}
      />
      <input ref={dateRef} type="date" className="text-sm bg-white/10 border border-white/20 rounded-md px-2 text-white" />
      <Button type="submit" size="icon" disabled={isPending} className="bg-white/20 hover:bg-white/30">
        <Plus className="h-4 w-4" />
      </Button>
    </form>
  )
}
```

## Acceptance Criteria
- [ ] Pressing `n` (when not in an input) focuses the title field
- [ ] `Enter` submits the form
- [ ] `Esc` blurs the title field
- [ ] Form resets after successful submit
- [ ] `useTransition` wraps the server action call (no blocking UI)
- [ ] Due date field is optional (empty = no due date)
- [ ] Disabled state shown while server action is pending

## Technical Notes
### UI Standard
Follow brainstorm.md UI/UX decisions: glassmorphism-style input (bg-white/10, border-white/20), dark mode. Reference: history/20260227-todo-app-nextjs16/brainstorm.md

- `useTransition` is preferred over `useState(loading)` for Server Action pending state
- Guard `n` shortcut: only fire when `event.target.tagName !== 'INPUT'`
- `type="date"` naturally produces `YYYY-MM-DD` format — no parsing needed
- `useRef` for inputs avoids controlled state re-renders on every keystroke
- Clean up the `keydown` event listener in the `useEffect` return
